impl Solution { pub fn find_farmland(mut land: Vec<Vec<i32>>) -> Vec<Vec<i32>> { let (m, n, mut black_res) = (land.len(), land[0].len(), vec![]); for r in 0..m { for c in 0..n { if land[r][c] == 1 { let (mut r2, mut c2) = (r, c); while r2 + 1 < m && land[r2 + 1][c] == 1 { r2 += 1; } while c2 + 1 < n && land[r][c2 + 1] == 1 { c2 += 1; } for i in r..=r2 { for j in c..=c2 { land[i][j] = 0; } } black_res.push(vec![r as i32, c as i32, r2 as i32, c2 as i32]); } } } black_res } }